DO $openmodels_seed_check$
DECLARE
  total_count INTEGER;
  enabled_count INTEGER;
  disabled_count INTEGER;
  pricing_option_count INTEGER;
  default_option_count INTEGER;
  non_community_option_count INTEGER;
  community_option_count INTEGER;
  default_model_count INTEGER;
  non_community_model_count INTEGER;
  community_model_count INTEGER;
BEGIN
  SELECT count(*)::integer,
         count(*) FILTER (WHERE enabled)::integer,
         count(*) FILTER (WHERE NOT enabled)::integer
    INTO total_count, enabled_count, disabled_count
  FROM _openmodels_provider_models_seed;

  IF total_count <> 494
     OR enabled_count <> 404
     OR disabled_count <> 90 THEN
    RAISE EXCEPTION
      'unexpected OpenModels seed counts: total=%, enabled=%, disabled=%',
      total_count, enabled_count, disabled_count;
  END IF;

  SELECT COALESCE(sum(jsonb_array_length(info->'pricing_options')), 0)::integer
    INTO pricing_option_count
  FROM _openmodels_provider_models_seed;

  IF pricing_option_count <> 432 THEN
    RAISE EXCEPTION
      'unexpected OpenModels pricing option count: %', pricing_option_count;
  END IF;

  SELECT count(*) FILTER (WHERE option->>'selection_reason' = 'default')::integer,
         count(*) FILTER (
           WHERE option->>'selection_reason' = 'non_community_lowest'
         )::integer,
         count(*) FILTER (
           WHERE option->>'selection_reason' = 'community_lowest'
         )::integer
    INTO default_option_count,
         non_community_option_count,
         community_option_count
  FROM _openmodels_provider_models_seed AS seed
  CROSS JOIN LATERAL jsonb_array_elements(seed.info->'pricing_options') AS option;

  IF default_option_count <> 17
     OR non_community_option_count <> 57
     OR community_option_count <> 358 THEN
    RAISE EXCEPTION
      'unexpected option selections: default=%, non_community=%, community=%',
      default_option_count, non_community_option_count, community_option_count;
  END IF;

  WITH model_reasons AS (
    SELECT CASE
             WHEN EXISTS (
               SELECT 1
               FROM jsonb_array_elements(seed.info->'pricing_options') AS option
               WHERE option->>'selection_reason' = 'default'
             ) THEN 'default'
             WHEN EXISTS (
               SELECT 1
               FROM jsonb_array_elements(seed.info->'pricing_options') AS option
               WHERE option->>'selection_reason' = 'non_community_lowest'
             ) THEN 'non_community_lowest'
             ELSE 'community_lowest'
           END AS reason
    FROM _openmodels_provider_models_seed AS seed
    WHERE seed.enabled
  )
  SELECT count(*) FILTER (WHERE reason = 'default')::integer,
         count(*) FILTER (WHERE reason = 'non_community_lowest')::integer,
         count(*) FILTER (WHERE reason = 'community_lowest')::integer
    INTO default_model_count,
         non_community_model_count,
         community_model_count
  FROM model_reasons;

  IF default_model_count <> 17
     OR non_community_model_count <> 54
     OR community_model_count <> 333 THEN
    RAISE EXCEPTION
      'unexpected model selections: default=%, non_community=%, community=%',
      default_model_count, non_community_model_count, community_model_count;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM _openmodels_provider_models_seed
    WHERE btrim(model_id) = ''
       OR model_id <> btrim(model_id)
       OR btrim(display_name) = ''
       OR jsonb_typeof(info) IS DISTINCT FROM 'object'
       OR jsonb_typeof(info->'pricing_options') IS DISTINCT FROM 'array'
  ) THEN
    RAISE EXCEPTION 'invalid OpenModels provider model payload';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM _openmodels_provider_models_seed AS seed
    WHERE (NOT seed.enabled AND jsonb_array_length(seed.info->'pricing_options') <> 0)
       OR (
         EXISTS (
           SELECT 1
           FROM jsonb_array_elements(seed.info->'pricing_options') AS option
           WHERE option->>'billing_unit' = 'token'
         )
         AND (
           jsonb_typeof(seed.info->'prompt') IS DISTINCT FROM 'number'
           OR jsonb_typeof(seed.info->'completion') IS DISTINCT FROM 'number'
         )
       )
       OR (
         EXISTS (
           SELECT 1
           FROM jsonb_array_elements(seed.info->'pricing_options') AS option
           WHERE option->>'billing_unit' = 'token'
         )
         AND NOT EXISTS (
           SELECT 1
           FROM jsonb_array_elements(seed.info->'pricing_options') AS option
           WHERE option->>'billing_unit' = 'token'
             AND abs(
                   (seed.info->>'prompt')::numeric
                   - (option->>'prompt_usd_per_unit')::numeric
                 ) <= 0.000000000000000001::numeric
             AND abs(
                   (seed.info->>'completion')::numeric
                   - (option->>'completion_usd_per_unit')::numeric
                 ) <= 0.000000000000000001::numeric
         )
       )
       OR (
         NOT EXISTS (
           SELECT 1
           FROM jsonb_array_elements(seed.info->'pricing_options') AS option
           WHERE option->>'billing_unit' = 'token'
         )
         AND (seed.info ? 'prompt' OR seed.info ? 'completion')
       )
  ) THEN
    RAISE EXCEPTION 'invalid token/non-token provider model price shape';
  END IF;

  IF EXISTS (
    WITH options AS (
      SELECT option,
             option->>'source_currency' AS currency,
             option->>'billing_type' AS billing_type,
             option->>'billing_unit' AS billing_unit,
             (option->>'source_prompt_micro')::numeric AS source_prompt,
             (option->>'source_completion_micro')::numeric AS source_completion,
             (option->>'prompt_usd_per_unit')::numeric AS actual_prompt,
             (option->>'completion_usd_per_unit')::numeric AS actual_completion
      FROM _openmodels_provider_models_seed AS seed
      CROSS JOIN LATERAL jsonb_array_elements(seed.info->'pricing_options') AS option
    ),
    calculated AS (
      SELECT *,
             source_prompt / 1000000::numeric
               / CASE currency WHEN 'CNY' THEN 6.78::numeric ELSE 1::numeric END
               / CASE billing_unit WHEN 'token' THEN 1000000::numeric ELSE 1::numeric END
               AS expected_prompt,
             source_completion / 1000000::numeric
               / CASE currency WHEN 'CNY' THEN 6.78::numeric ELSE 1::numeric END
               / CASE billing_unit WHEN 'token' THEN 1000000::numeric ELSE 1::numeric END
               AS expected_completion
      FROM options
    )
    SELECT 1
    FROM calculated
    WHERE currency IS NULL
       OR currency NOT IN ('USD', 'CNY')
       OR (
         (billing_type = 'duration' AND billing_unit = 'second')
         OR (billing_type = 'per_image' AND billing_unit = 'image')
         OR (billing_type = 'per_request' AND billing_unit = 'request')
         OR (billing_type = 'usage_flat' AND billing_unit = 'token')
         OR (billing_type = 'usage_tiered' AND billing_unit = 'request')
         OR (billing_type = 'usage_tiered' AND billing_unit = 'token')
       ) IS NOT TRUE
       OR jsonb_typeof(option->'source_prompt_micro') IS DISTINCT FROM 'number'
       OR jsonb_typeof(option->'source_completion_micro') IS DISTINCT FROM 'number'
       OR jsonb_typeof(option->'prompt_usd_per_unit') IS DISTINCT FROM 'number'
       OR jsonb_typeof(option->'completion_usd_per_unit') IS DISTINCT FROM 'number'
       OR source_prompt < 0
       OR source_completion < 0
       OR option->>'usd_amount_unit' IS DISTINCT FROM CASE billing_unit
            WHEN 'token' THEN 'USD_per_token'
            ELSE 'USD_per_' || billing_unit
          END
       OR option->>'source_amount_unit' IS DISTINCT FROM CASE
            WHEN billing_unit = 'token' THEN
              CASE currency
                WHEN 'USD' THEN 'microUSD_per_1m_tokens'
                ELSE 'microCNY_per_1m_tokens'
              END
            ELSE
              CASE currency WHEN 'USD' THEN 'microUSD' ELSE 'microCNY' END
              || '_per_' || billing_unit
          END
       OR abs(actual_prompt - expected_prompt) > greatest(
            abs(expected_prompt) * 0.000000000001::numeric,
            0.000000000000000001::numeric
          )
       OR abs(actual_completion - expected_completion) > greatest(
            abs(expected_completion) * 0.000000000001::numeric,
            0.000000000000000001::numeric
          )
  ) THEN
    RAISE EXCEPTION 'invalid OpenModels source-currency conversion';
  END IF;

  IF EXISTS (
    SELECT lower(model_id)
    FROM _openmodels_provider_models_seed
    GROUP BY lower(model_id)
    HAVING count(*) > 1
  ) THEN
    RAISE EXCEPTION 'case-insensitive duplicate OpenModels model_id';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM _openmodels_provider_models_seed AS seed
    JOIN public.provider_models AS existing
      ON existing.provider_id = 'db1cbfcb-8d6d-4a55-9ddb-c1e638738b38'::uuid
     AND lower(btrim(existing.model_id)) = lower(seed.model_id)
    WHERE existing.model_id <> seed.model_id
  ) THEN
    RAISE EXCEPTION
      'target database contains a case-insensitive OpenModels model_id conflict';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.provider_models AS existing
    WHERE existing.provider_id = 'db1cbfcb-8d6d-4a55-9ddb-c1e638738b38'::uuid
      AND NOT EXISTS (
        SELECT 1
        FROM _openmodels_provider_models_seed AS seed
        WHERE seed.model_id = existing.model_id
      )
  ) THEN
    RAISE EXCEPTION
      'target database contains OpenModels models outside this authoritative snapshot';
  END IF;
END
$openmodels_seed_check$;

INSERT INTO public.provider_models AS existing
  (provider_id, model_id, display_name, info, enabled)
SELECT 'db1cbfcb-8d6d-4a55-9ddb-c1e638738b38'::uuid,
       seed.model_id,
       seed.display_name,
       seed.info,
       seed.enabled
FROM _openmodels_provider_models_seed AS seed
ON CONFLICT (provider_id, model_id) DO UPDATE
SET display_name = EXCLUDED.display_name,
    info = EXCLUDED.info,
    enabled = EXCLUDED.enabled,
    updated_at = now()
WHERE (existing.display_name, existing.info, existing.enabled)
      IS DISTINCT FROM
      (EXCLUDED.display_name, EXCLUDED.info, EXCLUDED.enabled);

DO $openmodels_result_check$
DECLARE
  total_count INTEGER;
  enabled_count INTEGER;
  disabled_count INTEGER;
BEGIN
  SELECT count(*)::integer,
         count(*) FILTER (WHERE enabled)::integer,
         count(*) FILTER (WHERE NOT enabled)::integer
    INTO total_count, enabled_count, disabled_count
  FROM public.provider_models
  WHERE provider_id = 'db1cbfcb-8d6d-4a55-9ddb-c1e638738b38'::uuid;

  IF total_count <> 494
     OR enabled_count <> 404
     OR disabled_count <> 90 THEN
    RAISE EXCEPTION
      'unexpected persisted OpenModels counts: total=%, enabled=%, disabled=%',
      total_count, enabled_count, disabled_count;
  END IF;
END
$openmodels_result_check$;

SELECT count(*)::integer AS seeded_models,
       count(*) FILTER (WHERE model.enabled)::integer AS enabled_models,
       count(*) FILTER (WHERE NOT model.enabled)::integer AS disabled_models
FROM public.provider_models AS model
WHERE model.provider_id = 'db1cbfcb-8d6d-4a55-9ddb-c1e638738b38'::uuid;

COMMIT;


